  1	import { Given, Then, When } from '@badeball/cypress-cucumber-preprocessor';
  2	import { switchPerspective } from '../../constants/global';
  3	import { perspective } from '../../pages/app';
  4	
  5	Given('user is at Administrator perspective', () => {
  6	  perspective.switchTo(switchPerspective.Administrator);
  7	});
  8	
  9	When('user clicks on Pipelines Tab', () => {
 10	  cy.get('[data-test="nav-pipelines"]').then(($el) => {
 11	    if ($el.attr('aria-expanded') === 'false') {
 12	      cy.wrap($el).click();
 13	    }
 14	  });
 15	  cy.get('[data-test="nav"][data-quickstart-id="qs-nav-pipelines"]')
 16	    .contains('Pipelines')
 17	    .click();
 18	});
 19	
 20	When(
 21	  'user creates pipeline using YAML and CLI {string} in namespace {string}',
 22	  (yamlFile: string, namespace: string) => {
 23	    const fullPath = yamlFile.startsWith('cypress/')
 24	      ? yamlFile
 25	      : `cypress/${yamlFile}`;
 26	    cy.exec(`oc apply -f ${fullPath} -n ${namespace}`, {
 27	      failOnNonZeroExit: false,
 28	    }).then((result) => {
 29	      if (result.stderr) {
 30	        throw new Error(result.stderr);
 31	        /* cy.log('CLI failed, falling back to UI');
 32	        cy.get('[data-test="item-create"]').click();
 33	        cy.get('[data-test="list-page-create-dropdown-item-pipeline"]').click();
 34	        cy.get('[data-test="yaml-view-input"]').click();
 35	        cy.get('button').contains('Create').click();
 36	        cy.log('Pipeline created via UI'); */
 37	      }
 38	    });
 39	  },
 40	);
 41	
 42	Then(
 43	  'pipeline {string} should be created successfully in namespace {string}',
 44	  (pipelineName: string, namespace: string) => {
 45	    cy.exec(`oc get pipeline ${pipelineName} -n ${namespace}`, {
 46	      failOnNonZeroExit: false,
 47	    }).then((result) => {
 48	      if (result.code !== 0) {
 49	        throw new Error(
 50	          `Pipeline ${pipelineName} was not created successfully: ${result.stderr}`,
 51	        );
 52	      }
 53	      cy.log(`Pipeline ${pipelineName} created successfully`);
 54	    });
 55	  },
 56	);
 57	
 58	When(
 59	  'user creates pipeline run using YAML and CLI {string} in namespace {string}',
 60	  (yamlFile: string, namespace: string) => {
 61	    const fullPath = yamlFile.startsWith('cypress/')
 62	      ? yamlFile
 63	      : `cypress/${yamlFile}`;
 64	    cy.exec(`oc apply -f ${fullPath} -n ${namespace}`, {
 65	      failOnNonZeroExit: false,
 66	    }).then((result) => {
 67	      if (result.stderr) {
 68	        throw new Error(result.stderr);
 69	      }
 70	    });
 71	  },
 72	);
 73	
 74	Then(
 75	  'pipeline run {string} should be created successfully in namespace {string}',
 76	  (pipelineRunName: string, namespace: string) => {
 77	    cy.exec(`oc get pipelinerun ${pipelineRunName} -n ${namespace}`);
 78	    cy.exec(
 79	      `oc wait --for=condition=Succeeded pipelinerun/${pipelineRunName} -n ${namespace} --timeout=300s`,
 80	    );
 81	  },
 82	);
 83	
 84	Given(
 85	  'user is at pipeline run details page for {string} in namespace {string}',
 86	  (pipelineRunName: string, namespace: string) => {
 87	    cy.visit(
 88	      `/k8s/ns/${namespace}/tekton.dev~v1~PipelineRun/${pipelineRunName}`,
 89	    );
 90	  },
 91	);
 92	
 93	When(
 94	  'user navigates to Logs Tab for {string} in namespace {string}',
 95	  (pipelineRunName: string, namespace: string) => {
 96	    cy.visit(
 97	      `/k8s/ns/${namespace}/tekton.dev~v1~PipelineRun/${pipelineRunName}/logs`,
 98	    );
 99	  },
100	);
101	
102	Then('user should see {string} task in task list', (taskName: string) => {
103	  cy.get('[data-test-id="logs-tasklist"]')
104	    .contains(taskName)
105	    .should('be.visible');
106	});
107	
108	Given(
109	  'user tries to navigate to task {string} and step {string} in Logs tab using URL for {string} in namespace {string}',
110	  (
111	    taskName: string,
112	    stepName: string,
113	    pipelineRunName: string,
114	    namespace: string,
115	  ) => {
116	    cy.visit(
117	      `/k8s/ns/${namespace}/tekton.dev~v1~PipelineRun/${pipelineRunName}/logs?taskName=${taskName}&step=${stepName}`,
118	    );
119	  },
120	);
121	
122	Then(
123	  'user should see {string} step is visible in logs tab',
124	  (stepName: string) => {
125	    cy.contains(stepName).should('be.visible');
126	    cy.log(`${stepName} is visible in logs tab`);
127	    cy.visit('/');
128	  },
129	);
130	
131	Then(
132	  'user should expect default behavior of log viewer and scroll to end of log',
133	  () => {
134	    cy.get('.pf-v5-c-log-viewer__scroll-container').then(($el) => {
135	      const el = $el[0];
136	      //eslint-disable-next-line cypress/no-unnecessary-waiting
137	      cy.wait(2000);
138	      // Verifying if the scroll is at the bottom
139	      expect(el.scrollHeight - el.scrollTop).to.be.closeTo(el.clientHeight, 1);
140	      cy.visit('/');
141	    });
142	  },
143	);

